SELECT country_id, COUNT(result_id) AS total_search_results
FROM search_results
GROUP BY country_id;

SELECT url, landing_min_time
FROM search_results
ORDER BY landing_min_time DESC;

SELECT AVG(landing_click) AS average_landing_click
FROM search_results
WHERE device_type = 'mobile' AND browser_type = 'Chrome';

SELECT DISTINCT query 
FROM queries 
ORDER BY query;

SELECT DISTINCT device_type
FROM search_results
ORDER BY device_type ASC;
